import '../lib/connectivity_monitor.dart';
import '../lib/epoch_filter.dart';
import '../lib/lease_pool.dart';
import '../lib/source.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final leases = LeasePool();
  leases.add('panel-one');
  leases.add('panel-two');
  leases.remove('panel-one');
  check(leases.transportWanted, 'a nonempty lease set still wants transport');
  check(leases.ownerCount == 1, 'removing one owner retains the other lease');

  final epochs = EpochFilter();
  final retiredEpoch = epochs.open();
  epochs.close();
  final replacementEpoch = epochs.open();
  check(!epochs.accepts(retiredEpoch), 'a retired epoch stays invalid after reopen');
  check(epochs.accepts(replacementEpoch), 'the replacement epoch is accepted');

  final sharedSource = ManualStatusSource();
  final shared = ConnectivityMonitor(sharedSource);
  final remaining = <String>[];
  shared.attach('route-a', (_) {});
  shared.attach('route-b', remaining.add);
  final sharedBinding = sharedSource.bindings.single;
  sharedBinding.deliverLive('wifi');
  shared.detach('route-a');
  check(!sharedBinding.isClosed, 'one remaining lease keeps the source active');
  sharedBinding.deliverLive('cellular');
  check(remaining.last == 'cellular', 'the remaining route keeps receiving updates');

  final replaySource = ManualStatusSource();
  final replay = ConnectivityMonitor(replaySource);
  replay.attach('old-route', (_) {});
  replaySource.bindings.single.deliverLive('limited');
  final entered = <String>[];
  replay.attach('new-route', entered.add);
  check(
    entered.join(',') == 'limited',
    'a handoff observer receives the known state without waiting for a transition',
  );

  final epochSource = ManualStatusSource();
  final epochMonitor = ConnectivityMonitor(epochSource);
  epochMonitor.attach('before-suspend', (_) {});
  final retired = epochSource.bindings.single;
  retired.deliverLive('online');
  epochMonitor.detach('before-suspend');
  final resumed = <String>[];
  epochMonitor.attach('after-resume', resumed.add);
  epochSource.bindings.last.deliverLive('offline');
  retired.deliverQueued('online');
  check(
    resumed.join(',') == 'offline',
    'a queued callback from the retired binding cannot overwrite resumed state',
  );
}
